    {
      "input": {
        "flow": "route_parameter_policy",
        "events": [
          {
            "type": "login"
          },
          {
            "type": "visit",
            "url": "/ownProps/2"
          }
        ]
      },
      "expected_output": "path=/login\nsearch=?redirect=%2FownProps%2F2\nrendered=target\n"
    }
  ]
}

