Here are the public test cases for feature13_redirect_mechanisms:
{
  "description": "Redirects work through router context when no explicit dispatch action is supplied, and unchanged authorization state does not trigger duplicate redirect actions after mount.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "context_router_redirect",
        "events": [
          {
            "type": "visit",
            "url": "/noaction"
          }
        ]
      },
      "expected_output": "step=0\nevent=visit:/noaction\npath=/login\nsearch=?redirect=%2Fnoaction\nrendered=target\n"
    },
    {
      "input": {
        "flow": "single_redirect"
      },
      "expected_output": "redirect_calls_after_mount=1\nredirect_calls_after_auth_change=1\n"
    }
  ]
}

Here are the public test cases for feature1_redirect_unauthenticated:
{
  "description": "A protected route redirects an unauthenticated visitor to the login route and records the attempted URL in a query parameter.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "requires_session",
        "events": [
          {
            "type": "visit",
            "url": "/auth"
          }
        ]
      },
      "expected_output": "step=0\nevent=visit:/auth\npath=/login\nsearch=?redirect=%2Fauth\nrendered=target\n"
    },
    {
      "input": {
        "flow": "route_flow",
        "policy": "requires_session",
        "events": [
          {
            "type": "visit",
            "url": "/auth?test=foo"
          }
        ]
      },
      "expected_output": "step=0\nevent=visit:/auth?test=foo\npath=/login\nsearch=?redirect=%2Fauth%3Ftest%3Dfoo\nrendered=target\n"
    }
  ]
}

Here are the public test cases for feature2_pending_authentication:
{
  "description": "While authentication is still pending, the guarded route remains active and renders either the configured loading view or the default empty placeholder instead of redirecting.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "pending_custom_loading",
        "events": [
          {
            "type": "visit",
            "url": "/alwaysAuth"
          }
        ]
      },
      "expected_output": "step=0\nevent=visit:/alwaysAuth\npath=/alwaysAuth\nsearch=\nrendered=loading\n"
    },
    {
      "input": {
        "flow": "route_flow",
        "policy": "pending_default_loading",
        "events": [
          {
            "type": "visit",
            "url": "/alwaysAuthDef"
          }
        ]
      },
      "expected_output": "step=0\nevent=visit:/alwaysAuthDef\npath=/alwaysAuthDef\nsearch=\nrendered=empty\nplaceholder_props={}\n"
    }
  ]
}

Here are the public test cases for feature3_session_state_changes:
{
  "description": "A protected route allows a valid session, and if the session later becomes missing or authentication finishes unsuccessfully, the active route changes to the login route.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "requires_session",
        "events": [
          {
            "type": "login"
          },
          {
            "type": "visit",
            "url": "/auth"
          }
        ]
      },
      "expected_output": "step=0\nevent=login\npath=/\nsearch=\nrendered=empty\nstep=1\nevent=visit:/auth\npath=/auth\nsearch=\nrendered=target\n"
    },
    {
      "input": {
        "flow": "route_flow",
        "policy": "requires_session",
        "events": [
          {
            "type": "login"
          },
          {
            "type": "visit",
            "url": "/auth"
          },
          {
            "type": "logout"
          }
        ]
      },
      "expected_output": "step=0\nevent=login\npath=/\nsearch=\nrendered=empty\nstep=1\nevent=visit:/auth\npath=/auth\nsearch=\nrendered=target\nstep=2\nevent=logout\npath=/login\nsearch=?redirect=%2Fauth\nrendered=target\n"
    },
    {
      "input": {
        "flow": "route_flow",
        "policy": "requires_session",
        "events": [
          {
            "type": "start_authentication"
          },
          {
            "type": "visit",
            "url": "/auth"
          },
          {
            "type": "logout"
          }
        ]
      },
      "expected_output": "step=0\nevent=start_authentication\npath=/\nsearch=\nrendered=empty\nstep=1\nevent=visit:/auth\npath=/auth\nsearch=\nrendered=empty\nstep=2\nevent=logout\npath=/login\nsearch=?redirect=%2Fauth\nrendered=target\n"
    }
  ]
}

Here are the public test cases for feature4_predicate_authorization:
{
  "description": "Custom authorization rules may inspect session profile fields, deny mismatches with a redirect, and allow matching profiles to stay on the guarded route.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "first_name_rule",
        "events": [
          {
            "type": "login",
            "first_name": "NotTest",
            "last_name": "McDuderson"
          },
          {
            "type": "visit",
            "url": "/testOnly"
          },
          {
            "type": "login",
            "first_name": "Test",
            "last_name": "McDuderson"
          },
          {
            "type": "visit",
            "url": "/testOnly"
          }
        ]
      },
      "expected_output": "step=0\nevent=login\npath=/\nsearch=\nrendered=empty\nstep=1\nevent=visit:/testOnly\npath=/\nsearch=?redirect=%2FtestOnly\nrendered=empty\nstep=2\nevent=login\npath=/\nsearch=?redirect=%2FtestOnly\nrendered=empty\nstep=3\nevent=visit:/testOnly\npath=/testOnly\nsearch=\nrendered=target\n"
    }
  ]
}

