Here are the public test cases for feature6_composed_authorization:
{
  "description": "Multiple guarded layers on the same route must all authorize the session before the protected content is rendered.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "two_nested_name_rules",
        "events": [
          {
            "type": "login",
            "first_name": "NotTest",
            "last_name": "McDuderson"
          },
          {
            "type": "visit",
            "url": "/testMcDudersonOnly"
          },
          {
            "type": "login",
            "first_name": "Test",
            "last_name": "NotMcDuderson"
          },
          {
            "type": "visit",
            "url": "/testMcDudersonOnly"
          },
          {
            "type": "login",
            "first_name": "Test",
            "last_name": "McDuderson"
          },
          {
            "type": "visit",
            "url": "/testMcDudersonOnly"
          }
        ]
      },
      "expected_output": "step=0\nevent=login\npath=/\nsearch=\nrendered=empty\nstep=1\nevent=visit:/testMcDudersonOnly\npath=/\nsearch=?redirect=%2FtestMcDudersonOnly\nrendered=empty\nstep=2\nevent=login\npath=/\nsearch=?redirect=%2FtestMcDudersonOnly\nrendered=empty\nstep=3\nevent=visit:/testMcDudersonOnly\npath=/\nsearch=?redirect=%2FtestMcDudersonOnly\nrendered=empty\nstep=4\nevent=login\npath=/\nsearch=?redirect=%2FtestMcDudersonOnly\nrendered=empty\nstep=5\nevent=visit:/testMcDudersonOnly\npath=/testMcDudersonOnly\nsearch=\nrendered=target\n"
    }
  ]
}

Here are the public test cases for feature7_nested_routes:
{
  "description": "Guarded parent and child routes preserve the full nested URL when redirecting and allow the nested content when a valid session exists.",
  "cases": [
    {
      "input": {
        "flow": "route_flow",
        "policy": "nested_parent_child",
        "events": [
          {
            "type": "visit",
            "url": "/parent/child"
          },
          {
            "type": "login"
          },
          {
            "type": "visit",
            "url": "/parent/child"
          },
          {
            "type": "logout"
          }
        ]
      },
      "expected_output": "step=0\nevent=visit:/parent/child\npath=/login\nsearch=?redirect=%2Fparent%2Fchild\nrendered=target\nstep=1\nevent=login\npath=/login\nsearch=?redirect=%2Fparent%2Fchild\nrendered=target\nstep=2\nevent=visit:/parent/child\npath=/parent/child\nsearch=\nrendered=target\nstep=3\nevent=logout\npath=/login\nsearch=?redirect=%2Fparent%2Fchild\nrendered=target\n"
    }
  ]
}

